import React from 'react';

export default function AutomataSVG({ automata, type, highlightPath = [] }) {
  if (!automata || !automata.states) {
    return <div style={{ color: '#94a3b8', padding: '20px' }}>No automata generated</div>;
  }

  const states = automata.states;
  const radius = 28;
  const centerX = 300;
  const centerY = 180;
  const circleRadius = 120;

  const positions = {};
  states.forEach((state, i) => {
    const angle = (2 * Math.PI * i) / states.length;
    positions[state] = {
      x: centerX + circleRadius * Math.cos(angle),
      y: centerY + circleRadius * Math.sin(angle),
    };
  });

  const accepts = new Set(type === 'nfa' ? [automata.accept] : automata.accepts || []);

  // 1. GROUP TRANSITIONS: Combine multiple symbols between the same states
  const transitionMap = {};
  Object.entries(automata.transitions || {}).forEach(([from, trans]) => {
    Object.entries(trans).forEach(([symbol, to]) => {
      const destinations = Array.isArray(to) ? to : [to];
      destinations.forEach(dest => {
        const key = `${from}->${dest}`;
        if (!transitionMap[key]) {
          transitionMap[key] = { from, to: dest, symbols: [] };
        }
        if (!transitionMap[key].symbols.includes(symbol)) {
          transitionMap[key].symbols.push(symbol);
        }
      });
    });
  });

  const groupedTransitions = Object.values(transitionMap);

  return (
    <svg width="100%" height="400" viewBox="0 0 600 400">
      <defs>
        <marker id="arrow" markerWidth="8" markerHeight="8" refX="7" refY="4" orient="auto">
          <path d="M0,0 L8,4 L0,8 Z" fill="#94a3b8" />
        </marker>
      </defs>

      {groupedTransitions.map((t, i) => {
        const from = positions[t.from];
        const to = positions[t.to];
        if (!from || !to) return null;

        const labelText = t.symbols.join(', ');
        const highlighted = highlightPath.includes(t.from) && highlightPath.includes(t.to);
        const stroke = highlighted ? '#f59e0b' : '#475569';

        // ───────────────── SELF LOOP ─────────────────
        if (t.from === t.to) {
          const loopSize = 35;
          const path = `M ${from.x - 12} ${from.y - radius + 2} 
                        C ${from.x - 25} ${from.y - radius - loopSize}, 
                          ${from.x + 25} ${from.y - radius - loopSize}, 
                          ${from.x + 12} ${from.y - radius + 2}`;

          return (
            <g key={i}>
              <path d={path} fill="none" stroke={stroke} strokeWidth="2.5" markerEnd="url(#arrow)" />
              <text
                x={from.x}
                y={from.y - radius - 25}
                fill={symbolColor(labelText)}
                fontSize="12"
                textAnchor="middle"
                fontWeight="600"
              >
                {labelText}
              </text>
            </g>
          );
        }

        // ───────────────── STRAIGHT / CURVED EDGES ─────────────────
        const dx = to.x - from.x;
        const dy = to.y - from.y;
        const angle = Math.atan2(dy, dx);
        
        // Text rotation calculation
        let rot = angle * (180 / Math.PI);
        if (rot > 90 || rot < -90) rot += 180;

        const startX = from.x + radius * Math.cos(angle);
        const startY = from.y + radius * Math.sin(angle);
        const endX = to.x - radius * Math.cos(angle);
        const endY = to.y - radius * Math.sin(angle);

        const reverseExists = groupedTransitions.some(ot => ot.from === t.to && ot.to === t.from);
        const mx = (startX + endX) / 2;
        const my = (startY + endY) / 2;

        // Perpendicular vector for label offsetting
        const nx = -dy / Math.sqrt(dx * dx + dy * dy);
        const ny = dx / Math.sqrt(dx * dx + dy * dy);

        if (reverseExists) {
          const curveStrength = 30;
          const cx = mx + nx * curveStrength;
          const cy = my + ny * curveStrength;

          const path = `M ${startX} ${startY} Q ${cx} ${cy} ${endX} ${endY}`;
          const lx = mx + nx * (curveStrength * 0.7); // Place label slightly inside curve
          const ly = my + ny * (curveStrength * 0.7);

          return (
            <g key={i}>
              <path d={path} fill="none" stroke={stroke} strokeWidth="2.5" markerEnd="url(#arrow)" />
              <text
                transform={`translate(${lx}, ${ly}) rotate(${rot})`}
                fill={symbolColor(labelText)}
                fontSize="12"
                textAnchor="middle"
                dominantBaseline="central"
                fontWeight="600"
              >
                {labelText}
              </text>
            </g>
          );
        }

        // Straight line label offset
        return (
          <g key={i}>
            <path d={`M ${startX} ${startY} L ${endX} ${endY}`} fill="none" stroke={stroke} strokeWidth="2.5" markerEnd="url(#arrow)" />
            <text
              transform={`translate(${mx + nx * 12}, ${my + ny * 12}) rotate(${rot})`}
              fill={symbolColor(labelText)}
              fontSize="12"
              textAnchor="middle"
              dominantBaseline="central"
              fontWeight="600"
            >
              {labelText}
            </text>
          </g>
        );
      })}

      {states.map(state => {
        const pos = positions[state];
        const highlighted = highlightPath.includes(state);
        const isStart = state === automata.start;
        const isAccept = accepts.has(state);

        return (
          <g key={state}>
            <circle
              cx={pos.x}
              cy={pos.y}
              r={radius}
              fill={highlighted ? 'rgba(245,158,11,0.15)' : '#0f172a'}
              stroke={highlighted ? '#f59e0b' : '#475569'}
              strokeWidth="3"
            />
            <text
              x={pos.x}
              y={pos.y + 6}
              fill="white"
              fontSize="14"
              textAnchor="middle"
              fontWeight="bold"
            >
              {isStart && '→'}{state}{isAccept && '*'}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

function symbolColor(symbol) {
  return symbol.includes('ε') ? '#a78bfa' : '#cbd5e1';
}
